// Global: ~/.claude/settings.json — applies to ALL projects
{
  "permissions": {
    "deny": [
      "Bash(sudo *)",
      "Bash(rm -rf *)",
      "Write(**/.env)"
    ]
  }
}

// Project: .claude/settings.json — committed to git, shared with team
{
  "permissions": {
    "allow": [
      "Bash(npm run *)",
      "Bash(git *)",
      "Read(**)",
      "Write(src/**)",
      "Write(tests/**)"
    ],
    "deny": [
      "Bash(git push --force*)",
      "Bash(npm publish*)"
    ]
  }
}

// User-local: .claude/settings.local.json — gitignored, personal overrides
{
  "permissions": {
    "allow": [
      "Bash(npm publish --dry-run*)"   // personal: allow dry-run publishing to test
    ]
  }
}
